import os,json,base64,urllib.request,urllib.error
TOKEN=os.environ.get('GITHUB_TOKEN','')
U='DingiDinigi'
def push(repo,path,content,msg):
    url='https://api.github.com/repos/'+U+'/'+repo+'/contents/'+path
    b64=base64.b64encode(content.encode()).decode()
    data=json.dumps({'message':msg,'content':b64}).encode()
    headers={'Authorization':'token '+TOKEN,'Content-Type':'application/json','User-Agent':'py'}
    req=urllib.request.Request(url,data=data,headers=headers,method='PUT')
    try:
        with urllib.request.urlopen(req) as r:
            print('OK: '+repo+'/'+path)
    except urllib.error.HTTPError as e:
        print('FAIL: '+path+' '+e.read().decode()[:100])
